/**
 * One-time cleanup: removes fake/stub data created by old automation logic.
 * Safe to run multiple times (all deletes are conditional).
 *
 * Removes:
 *  - Fake backlink opportunities ("Authority opportunity 1-4" pointing at Yelp/Nextdoor etc.)
 *  - Internal draft published content records (hollow placeholders)
 *  - Stub published content with generic auto-generated titles
 *  - Stub content queue items with generic auto-generated titles
 *  - Listing consistency monitor placeholders
 */

import pg from "pg";

const { Client } = pg;

const client = new Client({ connectionString: process.env.DATABASE_URL });
await client.connect();

console.log("Starting stub data cleanup...\n");

// ── 1. Fake backlink opportunities ────────────────────────────────────────────
const backlinks = await client.query(`
  DELETE FROM backlink_opportunities
  WHERE source_name LIKE 'Authority opportunity%'
  RETURNING id
`);
console.log(`✓ Deleted ${backlinks.rowCount} fake backlink opportunity rows`);

// ── 2. Internal draft published content ──────────────────────────────────────
const drafts = await client.query(`
  DELETE FROM published_content
  WHERE channel = 'internal_draft'
     OR body LIKE 'Internal draft generated by recurring automation%'
  RETURNING id
`);
console.log(`✓ Deleted ${drafts.rowCount} internal_draft published content records`);

// ── 3. Stub published content with generic auto-generated titles ──────────────
const stubPublished = await client.query(`
  DELETE FROM published_content
  WHERE title LIKE 'Story %: local demand update'
     OR title LIKE 'Service-area story %: local proof update'
     OR title LIKE 'Draft article/page %'
  RETURNING id
`);
console.log(`✓ Deleted ${stubPublished.rowCount} stub published content records`);

// ── 4. Stub content queue items with generic titles ───────────────────────────
const stubQueue = await client.query(`
  DELETE FROM content_queue
  WHERE title LIKE 'Story %: local demand update'
     OR title LIKE 'Service-area story %: local proof update'
  RETURNING id
`);
console.log(`✓ Deleted ${stubQueue.rowCount} stub content queue items`);

// ── 5. Listing consistency monitor placeholders ───────────────────────────────
const monitors = await client.query(`
  DELETE FROM citation_monitors
  WHERE source_name LIKE 'Listing consistency monitor%'
  RETURNING id
`);
console.log(`✓ Deleted ${monitors.rowCount} placeholder citation monitor records`);

// ── 6. Synthetic AI visibility checks ────────────────────────────────────────
const syntheticAI = await client.query(`
  DELETE FROM ai_visibility_checks
  WHERE engine = 'synthetic'
     OR prompt LIKE 'recurring local-intent autopilot probe%'
  RETURNING id
`);
console.log(`✓ Deleted ${syntheticAI.rowCount} synthetic AI visibility check records`);

await client.end();
console.log("\nCleanup complete.");
